mapper.select:
SELECT r.orderno AS orderNo, MAX(r.retailtime) AS retailtime, MAX(r.operateperson) AS operateperson, MAX(r.paytype) AS paytype, MAX(r.remark) AS remark, SUM(CASE WHEN IFNULL(r.order_status, 0) = 0 THEN r.number ELSE 0 END) AS totalNumber, SUM(CASE WHEN IFNULL(r.order_status, 0) = 0 THEN r.retailprice * r.number ELSE 0 END) AS totalAmount, COUNT(*) AS itemCount, MIN(CASE WHEN IFNULL(r.order_status, 0) = 1 THEN 1 ELSE 0 END) AS orderStatus FROM bus_retail r
r.isdelete = 0 AND r.orderno IS NOT NULL
AND r.paytype = #{vo.paytype}
AND r.retailtime >= #{vo.startTime}
AND r.retailtime <= #{vo.endTime}
GROUP BY r.orderno ORDER BY MAX(r.retailtime) DESC

SELECT l.id AS id, l.order_no AS orderNo, l.type AS type, IFNULL(g.goodsname, '') AS goodsName, IFNULL(g.size, '') AS goodsSize, l.number AS number, l.price AS price, l.price * l.number AS totalAmount, l.paytype AS paytype, l.operate_person AS operatePerson, IFNULL(DATE_FORMAT(l.operate_time, '%Y-%m-%d %H:%i:%s'), '') AS operateTime, l.remark AS remark FROM bus_retail_log l LEFT JOIN bus_goods g ON g.id = l.goods_id
AND l.order_no = #{vo.orderNo}
AND l.type = #{vo.recordType}
AND l.operate_time >= #{vo.startTime}
AND l.operate_time <= #{vo.endTime}
ORDER BY l.operate_time DESC
